package com.grit.liferecorder.ui.habits
import androidx.compose.foundation.ExperimentalFoundationApi; import androidx.compose.foundation.combinedClickable; import androidx.compose.foundation.layout.*; import androidx.compose.foundation.lazy.*; import androidx.compose.material3.*; import androidx.compose.runtime.*; import androidx.compose.ui.Modifier; import androidx.compose.ui.text.font.FontWeight; import androidx.compose.ui.unit.dp; import androidx.lifecycle.compose.collectAsStateWithLifecycle; import com.grit.liferecorder.data.local.entity.TrackedActionEntity
@Composable fun HabitsScreen(viewModel:HabitsViewModel,padding:PaddingValues){ val state by viewModel.state.collectAsStateWithLifecycle(); var name by remember{mutableStateOf("")}; var label by remember{mutableStateOf("Neutral")}; var logging by remember{mutableStateOf<TrackedActionEntity?>(null)}; LazyColumn(Modifier.padding(padding).fillMaxSize(),contentPadding=PaddingValues(16.dp),verticalArrangement=Arrangement.spacedBy(12.dp)){ item{ Text("Tracked Actions",style=MaterialTheme.typography.headlineMedium); Text("Tap to edit. Long press to quick log with the default label.",color=MaterialTheme.colorScheme.onSurfaceVariant) }; item{ OutlinedTextField(name,{name=it},label={Text("New action name")},modifier=Modifier.fillMaxWidth()); Row(horizontalArrangement=Arrangement.spacedBy(8.dp)){ listOf("Positive","Negative","Neutral").forEach{ FilterChip(selected=label==it,onClick={label=it},label={Text(it)}) }; Button(onClick={viewModel.add(name,label); name=""}){Text("Add")} } }; items(state.actions,key={it.id}){ TrackedActionCard(it,{},{logging=it}) } }; logging?.let{ LogActionDialog(it,onDismiss={logging=null},onSave={l,n->viewModel.log(it,l,n);logging=null}) } }
@OptIn(ExperimentalFoundationApi::class) @Composable fun TrackedActionCard(action:TrackedActionEntity,onClick:()->Unit,onLong:()->Unit){ Card(Modifier.fillMaxWidth().combinedClickable(onClick=onClick,onLongClick=onLong)){ Column(Modifier.padding(16.dp)){ Text(action.name,fontWeight=FontWeight.Bold); Text("Default label: ${action.defaultLabel} • ${if(action.isActive)"Active" else "Inactive"}",color=MaterialTheme.colorScheme.onSurfaceVariant) } } }
@Composable fun LogActionDialog(action:TrackedActionEntity,onDismiss:()->Unit,onSave:(String,String?)->Unit){ var label by remember{mutableStateOf(action.defaultLabel)}; var note by remember{mutableStateOf("")}; AlertDialog(onDismissRequest=onDismiss,confirmButton={Button(onClick={onSave(label,note.takeIf{it.isNotBlank()})}){Text("Save")}},dismissButton={TextButton(onClick=onDismiss){Text("Cancel")}},title={Text("Log ${action.name}")},text={Column(verticalArrangement=Arrangement.spacedBy(8.dp)){ Row(horizontalArrangement=Arrangement.spacedBy(8.dp)){ listOf("Positive","Negative","Neutral").forEach{ FilterChip(selected=label==it,onClick={label=it},label={Text(it)}) } }; OutlinedTextField(note,{note=it},label={Text("Optional note")}) }}) }
@Composable fun TrackedActionList(actions:List<TrackedActionEntity>){ Column{actions.forEach{Text(it.name)}} }
@Composable fun TrackedActionEditorScreen(){ Text("Tracked action editor with name, description, label, category, project, active toggle, save and delete.") }
@Composable fun ActionLogHistoryScreen(){ Text("Action log history") }
